import{_ as t,c as i,o as a,a2 as r}from"./chunks/framework.CIiVzG-O.js";const m=JSON.parse('{"title":"Usage Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/usage.md","filePath":"guide/usage.md","lastUpdated":1781417556000}'),n={name:"guide/usage.md"};function o(s,e,l,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="usage-guide" tabindex="-1">Usage Guide <a class="header-anchor" href="#usage-guide" aria-label="Permalink to &quot;Usage Guide&quot;">​</a></h1><h2 id="creating-reminders" tabindex="-1">Creating Reminders <a class="header-anchor" href="#creating-reminders" aria-label="Permalink to &quot;Creating Reminders&quot;">​</a></h2><h3 id="add-a-new-reminder" tabindex="-1">Add a New Reminder <a class="header-anchor" href="#add-a-new-reminder" aria-label="Permalink to &quot;Add a New Reminder&quot;">​</a></h3><ol><li>Open PetReminder</li><li>Click the <strong>+</strong> button or press <code>Cmd+N</code></li><li>Enter a title and message for your reminder</li><li>Set the date and time</li><li>Choose a pet to accompany this reminder (default pet if none selected)</li><li>Click <strong>Save</strong></li></ol><h3 id="recurring-reminders" tabindex="-1">Recurring Reminders <a class="header-anchor" href="#recurring-reminders" aria-label="Permalink to &quot;Recurring Reminders&quot;">​</a></h3><ul><li>Set frequency: daily, weekly, monthly, or custom intervals</li><li>Choose specific days of the week</li><li>Set an end date or no end date</li></ul><h3 id="managing-reminders" tabindex="-1">Managing Reminders <a class="header-anchor" href="#managing-reminders" aria-label="Permalink to &quot;Managing Reminders&quot;">​</a></h3><ul><li><strong>View</strong>: All reminders are shown in a list with their schedule and assigned pet</li><li><strong>Edit</strong>: Click any reminder to modify its settings</li><li><strong>Delete</strong>: Swipe or right-click a reminder to remove it</li><li><strong>Toggle</strong>: Enable or disable a reminder without deleting it</li></ul><h2 id="when-a-reminder-fires" tabindex="-1">When a Reminder Fires <a class="header-anchor" href="#when-a-reminder-fires" aria-label="Permalink to &quot;When a Reminder Fires&quot;">​</a></h2><p>When a reminder is triggered:</p><ol><li>A desktop pet appears on your screen</li><li>The pet walks around, sits, or performs unique animations</li><li>The reminder message is displayed with the pet</li><li>You can dismiss the pet by clicking on it or pressing <code>Esc</code></li></ol><h2 id="pet-interaction" tabindex="-1">Pet Interaction <a class="header-anchor" href="#pet-interaction" aria-label="Permalink to &quot;Pet Interaction&quot;">​</a></h2><h3 id="default-pet" tabindex="-1">Default Pet <a class="header-anchor" href="#default-pet" aria-label="Permalink to &quot;Default Pet&quot;">​</a></h3><ul><li>A free default pet comes with the app</li><li>Watch it move, sit, and react when you interact</li></ul><h3 id="changing-pets" tabindex="-1">Changing Pets <a class="header-anchor" href="#changing-pets" aria-label="Permalink to &quot;Changing Pets&quot;">​</a></h3><ol><li>Open <strong>Settings</strong> → <strong>Pet</strong></li><li>Select from your available pets</li><li>The selected pet will appear for future reminders</li></ol><h3 id="purchasing-pets" tabindex="-1">Purchasing Pets <a class="header-anchor" href="#purchasing-pets" aria-label="Permalink to &quot;Purchasing Pets&quot;">​</a></h3><p>See the <a href="/guide/pets.html">Pets &amp; IAP guide</a> for details on available premium pets.</p><h2 id="customization" tabindex="-1">Customization <a class="header-anchor" href="#customization" aria-label="Permalink to &quot;Customization&quot;">​</a></h2><h3 id="pet-appearance" tabindex="-1">Pet Appearance <a class="header-anchor" href="#pet-appearance" aria-label="Permalink to &quot;Pet Appearance&quot;">​</a></h3><ul><li>Some pets have customizable colors or patterns</li><li>Adjust animation speed and idle behavior</li></ul><h3 id="sound-settings" tabindex="-1">Sound Settings <a class="header-anchor" href="#sound-settings" aria-label="Permalink to &quot;Sound Settings&quot;">​</a></h3><ul><li>Enable/disable pet sound effects</li><li>Adjust volume independently from system volume</li><li>Choose from different sound themes</li></ul><h3 id="notification-style" tabindex="-1">Notification Style <a class="header-anchor" href="#notification-style" aria-label="Permalink to &quot;Notification Style&quot;">​</a></h3><ul><li>Choose between banner, alert, or silent notifications</li><li>Configure whether the pet appears in full-screen mode</li></ul><h2 id="keyboard-shortcuts" tabindex="-1">Keyboard Shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard Shortcuts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Shortcut</th><th>Action</th></tr></thead><tbody><tr><td><code>Cmd+N</code></td><td>New reminder</td></tr><tr><td><code>Cmd+,</code></td><td>Open settings</td></tr><tr><td><code>Cmd+W</code></td><td>Close window</td></tr><tr><td><code>Cmd+Q</code></td><td>Quit application</td></tr><tr><td><code>Esc</code></td><td>Dismiss pet</td></tr><tr><td><code>Space</code></td><td>Pause/resume reminder</td></tr></tbody></table><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>Access settings through <strong>PetReminder → Settings</strong> or press <code>Cmd+,</code>:</p><ul><li><strong>General</strong>: Language, launch at login, theme</li><li><strong>Reminders</strong>: Default reminder settings, notification preferences</li><li><strong>Pet</strong>: Choose pet, customize appearance and behavior</li><li><strong>Sound</strong>: Pet sound effects and volume</li><li><strong>Privacy</strong>: Data collection preferences</li></ul><h2 id="tips-and-tricks" tabindex="-1">Tips and Tricks <a class="header-anchor" href="#tips-and-tricks" aria-label="Permalink to &quot;Tips and Tricks&quot;">​</a></h2><ul><li>Use descriptive reminder messages — the pet will display them</li><li>Assign different pets to different types of reminders</li><li>Enable &quot;Launch at Login&quot; to never miss a reminder</li><li>Try different pet combinations for various moods</li><li>Check the <a href="/guide/pets.html">Pets &amp; IAP guide</a> to see all available breeds</li></ul>',32)])])}const g=t(n,[["render",o]]);export{m as __pageData,g as default};
